+/**
+ * User notification preferences model.
+ *
+ * Controls how and when a user receives notifications.
+ * Currently supports email as the only channel — designed to be
+ * extended with additional channels (SMS, push, etc.) later.
+ */
+
+import type { NotificationType } from './notification.js';
+
+/**
+ * Email delivery frequency.
+ * - 'immediate': send as soon as the event occurs
+ * - 'daily-digest': batch into a daily summary
+ * - 'weekly-digest': batch into a weekly summary
+ */
+export type EmailFrequency = 'immediate' | 'daily-digest' | 'weekly-digest';
+
+/**
+ * Quiet hours configuration — notifications are suppressed during this window.
+ * Hours are in 24-hour format (0–23).
+ */
+export interface QuietHours {
+  /** Start hour (inclusive), 0–23. */
+  start: number;
+  /** End hour (exclusive), 0–23. */
+  end: number;
+}
+
+/**
+ * User notification preferences.
+ */
+export interface UserPreferences {
+  /** Unique preferences ID. */
+  id: string;
+  /** The user these preferences belong to. */
+  userId: string;
+  /** Global toggle for email notifications. */
+  emailEnabled: boolean;
+  /** Which notification categories the user wants to receive via email. */
+  emailCategories: NotificationType[];
+  /** How often email notifications should be delivered. */
+  emailFrequency: EmailFrequency;
+  /** Optional quiet hours — suppress notifications during this window. */
+  quietHours?: QuietHours;
+  createdAt: Date;
+  updatedAt: Date;
+}
+
+/**
+ * Input for creating user preferences.
+ */
+export interface CreateUserPreferencesInput {
+  userId: string;
+  emailEnabled?: boolean;
+  emailCategories?: NotificationType[];
+  emailFrequency?: EmailFrequency;
+  quietHours?: QuietHours;
+}
+
+/**
+ * Input for updating user preferences.
+ */
+export interface UpdateUserPreferencesInput {
+  emailEnabled?: boolean;
+  emailCategories?: NotificationType[];
+  emailFrequency?: EmailFrequency;
+  quietHours?: QuietHours | null;
+}
+
+/**
+ * All notification categories — used as the default subscription set.
+ */
+export const ALL_NOTIFICATION_CATEGORIES: NotificationType[] = [
+  'order-confirmation',
+  'order-status-update',
+  'welcome',
+  'account-updated',
+];
+
+/**
+ * Default preferences for new users.
+ */
+export const DEFAULT_PREFERENCES: Omit<UserPreferences, 'id' | 'userId' | 'createdAt' | 'updatedAt'> = {
+  emailEnabled: true,
+  emailCategories: [...ALL_NOTIFICATION_CATEGORIES],
+  emailFrequency: 'immediate',
+};

