diff --git a/src/services/preferences.service.ts b/src/services/preferences.service.ts
new file mode 100644
index 0000000..f222f53
--- /dev/null
+++ b/src/services/preferences.service.ts
@@ -0,0 +1,201 @@
+/**
+ * Preferences service — manages user notification preferences.
+ *
+ * Provides CRUD operations for user notification settings and a
+ * shouldSendEmail() check used by the notification service to
+ * decide whether a notification should be delivered.
+ */
+
+import type { PreferencesRepository } from '../repositories/preferences.repository.js';
+import type {
+  UserPreferences,
+  CreateUserPreferencesInput,
+  UpdateUserPreferencesInput,
+} from '../models/user-preferences.js';
+import type { NotificationType } from '../models/notification.js';
+import { ALL_NOTIFICATION_CATEGORIES, DEFAULT_PREFERENCES } from '../models/user-preferences.js';
+import { Logger } from '../utils/logger.js';
+
+let nextId = 1;
+
+function generatePreferencesId(): string {
+  return `pref-${String(nextId++).padStart(4, '0')}`;
+}
+
+/** Reset the ID counter. Useful for testing. */
+export function resetPreferencesIdCounter(): void {
+  nextId = 1;
+}
+
+export class PreferencesService {
+  private logger = new Logger('PreferencesService');
+
+  constructor(private repository: PreferencesRepository) {}
+
+  /**
+   * Get preferences for a user. Returns undefined if none exist.
+   */
+  getPreferences(userId: string): UserPreferences | undefined {
+    return this.repository.findByUserId(userId);
+  }
+
+  /**
+   * Get preferences for a user, creating defaults if none exist.
+   */
+  getOrCreatePreferences(userId: string): UserPreferences {
+    const existing = this.repository.findByUserId(userId);
+    if (existing) {
+      return existing;
+    }
+    return this.createPreferences({ userId });
+  }
+
+  /**
+   * Create preferences for a user.
+   * Merges provided input with defaults.
+   */
+  createPreferences(input: CreateUserPreferencesInput): UserPreferences {
+    const existing = this.repository.findByUserId(input.userId);
+    if (existing) {
+      throw new Error(`Preferences already exist for user: ${input.userId}`);
+    }
+
+    const now = new Date();
+    const preferences: UserPreferences = {
+      id: generatePreferencesId(),
+      userId: input.userId,
+      emailEnabled: input.emailEnabled ?? DEFAULT_PREFERENCES.emailEnabled,
+      emailCategories: input.emailCategories ?? [...DEFAULT_PREFERENCES.emailCategories],
+      emailFrequency: input.emailFrequency ?? DEFAULT_PREFERENCES.emailFrequency,
+      quietHours: input.quietHours,
+      createdAt: now,
+      updatedAt: now,
+    };
+
+    this.repository.save(preferences);
+    this.logger.info(`Created preferences for user: ${input.userId}`);
+    return preferences;
+  }
+
+  /**
+   * Update preferences for a user.
+   */
+  updatePreferences(userId: string, input: UpdateUserPreferencesInput): UserPreferences {
+    const existing = this.repository.findByUserId(userId);
+    if (!existing) {
+      throw new Error(`Preferences not found for user: ${userId}`);
+    }
+
+    const updates: Partial<UserPreferences> = { updatedAt: new Date() };
+
+    if (input.emailEnabled !== undefined) {
+      updates.emailEnabled = input.emailEnabled;
+    }
+    if (input.emailCategories !== undefined) {
+      updates.emailCategories = input.emailCategories;
+    }
+    if (input.emailFrequency !== undefined) {
+      updates.emailFrequency = input.emailFrequency;
+    }
+    if (input.quietHours !== undefined) {
+      updates.quietHours = input.quietHours === null ? undefined : input.quietHours;
+    }
+
+    const updated = this.repository.update(existing.id, updates);
+    this.logger.info(`Updated preferences for user: ${userId}`);
+    return updated;
+  }
+
+  /**
+   * Check whether an email notification should be sent to a user.
+   *
+   * Returns true if:
+   * 1. Email is globally enabled for the user
+   * 2. The notification type is in the user's subscribed categories
+   * 3. The current time is outside quiet hours (if configured)
+   *
+   * If no preferences exist for the user, returns true (opt-out model).
+   */
+  shouldSendEmail(userId: string, notificationType: NotificationType, now?: Date): boolean {
+    const prefs = this.repository.findByUserId(userId);
+
+    // No preferences = default behavior (send everything)
+    if (!prefs) {
+      return true;
+    }
+
+    // Global email toggle
+    if (!prefs.emailEnabled) {
+      this.logger.debug(`Email disabled for user ${userId}`);
+      return false;
+    }
+
+    // Category check
+    if (!prefs.emailCategories.includes(notificationType)) {
+      this.logger.debug(
+        `User ${userId} not subscribed to category: ${notificationType}`,
+      );
+      return false;
+    }
+
+    // Quiet hours check
+    if (prefs.quietHours) {
+      const currentHour = (now ?? new Date()).getHours();
+      if (isInQuietHours(currentHour, prefs.quietHours.start, prefs.quietHours.end)) {
+        this.logger.debug(`User ${userId} is in quiet hours`);
+        return false;
+      }
+    }
+
+    return true;
+  }
+
+  /**
+   * Subscribe a user to a notification category.
+   */
+  subscribeToCategory(userId: string, category: NotificationType): UserPreferences {
+    const prefs = this.getOrCreatePreferences(userId);
+    if (prefs.emailCategories.includes(category)) {
+      return prefs;
+    }
+    return this.updatePreferences(userId, {
+      emailCategories: [...prefs.emailCategories, category],
+    });
+  }
+
+  /**
+   * Unsubscribe a user from a notification category.
+   */
+  unsubscribeFromCategory(userId: string, category: NotificationType): UserPreferences {
+    const prefs = this.getOrCreatePreferences(userId);
+    return this.updatePreferences(userId, {
+      emailCategories: prefs.emailCategories.filter((c) => c !== category),
+    });
+  }
+
+  /**
+   * Reset a user's preferences to defaults.
+   */
+  resetToDefaults(userId: string): UserPreferences {
+    const prefs = this.getOrCreatePreferences(userId);
+    return this.updatePreferences(userId, {
+      emailEnabled: DEFAULT_PREFERENCES.emailEnabled,
+      emailCategories: [...ALL_NOTIFICATION_CATEGORIES],
+      emailFrequency: DEFAULT_PREFERENCES.emailFrequency,
+      quietHours: null,
+    });
+  }
+}
+
+/**
+ * Check if a given hour falls within quiet hours.
+ * Handles wrap-around (e.g., start=22, end=7 means 22:00–07:00).
+ */
+function isInQuietHours(currentHour: number, start: number, end: number): boolean {
+  if (start <= end) {
+    // Simple range: e.g., 9–17
+    return currentHour >= start && currentHour < end;
+  }
+  // Wrap-around: e.g., 22–7
+  return currentHour >= start || currentHour < end;
+}

