+import { describe, it, expect, beforeEach } from 'vitest';
+import { Database } from '../../src/utils/database.js';
+import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
+import {
+  PreferencesService,
+  resetPreferencesIdCounter,
+} from '../../src/services/preferences.service.js';
+import { ALL_NOTIFICATION_CATEGORIES } from '../../src/models/user-preferences.js';
+
+describe('PreferencesService', () => {
+  let db: Database;
+  let repository: PreferencesRepository;
+  let service: PreferencesService;
+
+  beforeEach(() => {
+    db = new Database();
+    repository = new PreferencesRepository(db);
+    service = new PreferencesService(repository);
+    resetPreferencesIdCounter();
+  });
+
+  describe('createPreferences', () => {
+    it('should create preferences with defaults', () => {
+      const prefs = service.createPreferences({ userId: 'user-1' });
+
+      expect(prefs.userId).toBe('user-1');
+      expect(prefs.emailEnabled).toBe(true);
+      expect(prefs.emailCategories).toEqual(ALL_NOTIFICATION_CATEGORIES);
+      expect(prefs.emailFrequency).toBe('immediate');
+      expect(prefs.quietHours).toBeUndefined();
+      expect(prefs.id).toBe('pref-0001');
+    });
+
+    it('should create preferences with custom values', () => {
+      const prefs = service.createPreferences({
+        userId: 'user-1',
+        emailEnabled: false,
+        emailCategories: ['order-confirmation'],
+        emailFrequency: 'daily-digest',
+        quietHours: { start: 22, end: 7 },
+      });
+
+      expect(prefs.emailEnabled).toBe(false);
+      expect(prefs.emailCategories).toEqual(['order-confirmation']);
+      expect(prefs.emailFrequency).toBe('daily-digest');
+      expect(prefs.quietHours).toEqual({ start: 22, end: 7 });
+    });
+
+    it('should throw if preferences already exist for user', () => {
+      service.createPreferences({ userId: 'user-1' });
+
+      expect(() => service.createPreferences({ userId: 'user-1' })).toThrow(
+        'Preferences already exist for user: user-1',
+      );
+    });
+
+    it('should generate sequential IDs', () => {
+      const prefs1 = service.createPreferences({ userId: 'user-1' });
+      const prefs2 = service.createPreferences({ userId: 'user-2' });
+
+      expect(prefs1.id).toBe('pref-0001');
+      expect(prefs2.id).toBe('pref-0002');
+    });
+  });
+
+  describe('getPreferences', () => {
+    it('should return undefined for unknown user', () => {
+      expect(service.getPreferences('user-unknown')).toBeUndefined();
+    });
+
+    it('should return existing preferences', () => {
+      service.createPreferences({ userId: 'user-1' });
+      const prefs = service.getPreferences('user-1');
+
+      expect(prefs).toBeDefined();
+      expect(prefs!.userId).toBe('user-1');
+    });
+  });
+
+  describe('getOrCreatePreferences', () => {
+    it('should create defaults if none exist', () => {
+      const prefs = service.getOrCreatePreferences('user-1');
+
+      expect(prefs.userId).toBe('user-1');
+      expect(prefs.emailEnabled).toBe(true);
+    });
+
+    it('should return existing preferences without creating new ones', () => {
+      service.createPreferences({
+        userId: 'user-1',
+        emailEnabled: false,
+      });
+
+      const prefs = service.getOrCreatePreferences('user-1');
+      expect(prefs.emailEnabled).toBe(false);
+    });
+  });
+
+  describe('updatePreferences', () => {
+    it('should update emailEnabled', () => {
+      service.createPreferences({ userId: 'user-1' });
+      const updated = service.updatePreferences('user-1', { emailEnabled: false });
+
+      expect(updated.emailEnabled).toBe(false);
+    });
+
+    it('should update emailCategories', () => {
+      service.createPreferences({ userId: 'user-1' });
+      const updated = service.updatePreferences('user-1', {
+        emailCategories: ['welcome'],
+      });
+
+      expect(updated.emailCategories).toEqual(['welcome']);
+    });
+
+    it('should update emailFrequency', () => {
+      service.createPreferences({ userId: 'user-1' });
+      const updated = service.updatePreferences('user-1', {
+        emailFrequency: 'weekly-digest',
+      });
+
+      expect(updated.emailFrequency).toBe('weekly-digest');
+    });
+
+    it('should set quiet hours', () => {
+      service.createPreferences({ userId: 'user-1' });
+      const updated = service.updatePreferences('user-1', {
+        quietHours: { start: 22, end: 7 },
+      });
+
+      expect(updated.quietHours).toEqual({ start: 22, end: 7 });
+    });
+
+    it('should clear quiet hours with null', () => {
+      service.createPreferences({
+        userId: 'user-1',
+        quietHours: { start: 22, end: 7 },
+      });
+      const updated = service.updatePreferences('user-1', { quietHours: null });
+
+      expect(updated.quietHours).toBeUndefined();
+    });
+
+    it('should throw for unknown user', () => {
+      expect(() =>
+        service.updatePreferences('user-unknown', { emailEnabled: false }),
+      ).toThrow('Preferences not found for user: user-unknown');
+    });
+
+    it('should update the updatedAt timestamp', () => {
+      const prefs = service.createPreferences({ userId: 'user-1' });
+      const originalUpdatedAt = prefs.updatedAt;
+
+      const updated = service.updatePreferences('user-1', { emailEnabled: false });
+      expect(updated.updatedAt.getTime()).toBeGreaterThanOrEqual(originalUpdatedAt.getTime());
+    });
+  });
+
+  describe('shouldSendEmail', () => {
+    it('should return true when no preferences exist (opt-out model)', () => {
+      expect(service.shouldSendEmail('user-unknown', 'order-confirmation')).toBe(true);
+    });
+
+    it('should return true when email is enabled and category is subscribed', () => {
+      service.createPreferences({ userId: 'user-1' });
+      expect(service.shouldSendEmail('user-1', 'order-confirmation')).toBe(true);
+    });
+
+    it('should return false when email is globally disabled', () => {
+      service.createPreferences({ userId: 'user-1', emailEnabled: false });
+      expect(service.shouldSendEmail('user-1', 'order-confirmation')).toBe(false);
+    });
+
+    it('should return false when category is not subscribed', () => {
+      service.createPreferences({
+        userId: 'user-1',
+        emailCategories: ['welcome'],
+      });
+
+      expect(service.shouldSendEmail('user-1', 'order-confirmation')).toBe(false);
+      expect(service.shouldSendEmail('user-1', 'welcome')).toBe(true);
+    });
+
+    it('should return false during quiet hours (simple range)', () => {
+      service.createPreferences({
+        userId: 'user-1',
+        quietHours: { start: 22, end: 7 },
+      });
+
+      // 23:00 is in quiet hours (22-7 wrap-around)
+      const lateNight = new Date('2026-04-02T23:00:00');
+      expect(service.shouldSendEmail('user-1', 'order-confirmation', lateNight)).toBe(false);
+
+      // 3:00 is in quiet hours (22-7 wrap-around)
+      const earlyMorning = new Date('2026-04-02T03:00:00');
+      expect(service.shouldSendEmail('user-1', 'order-confirmation', earlyMorning)).toBe(false);
+    });
+
+    it('should return true outside quiet hours', () => {
+      service.createPreferences({
+        userId: 'user-1',
+        quietHours: { start: 22, end: 7 },
+      });
+
+      // 12:00 is outside quiet hours
+      const noon = new Date('2026-04-02T12:00:00');
+      expect(service.shouldSendEmail('user-1', 'order-confirmation', noon)).toBe(true);
+    });
+
+    it('should handle non-wrapping quiet hours', () => {
+      service.createPreferences({
+        userId: 'user-1',
+        quietHours: { start: 9, end: 17 },
+      });
+
+      // 12:00 is in quiet hours (9-17)
